/**
 * Extract a usable image URL from a value that might be:
 *   • A plain string URL ("https://..." or "data:..." or a Cloudinary public_id)
 *   • An object with a `.url` or `.secure_url` field  (old upload shape)
 *   • null / undefined / empty string / "[object Object]"
 *
 * Returns a non-empty string or null.
 */
function extractImageUrl(raw) {
  if (!raw) return null;
  // Object with url/secure_url (e.g. {url: '...', public_id: '...'})
  if (typeof raw === 'object') {
    const u = raw.url || raw.secure_url || raw.imageUrl || null;
    return u ? String(u).trim() || null : null;
  }
  const s = String(raw).trim();
  // Reject obviously-broken values
  if (!s || s === '[object Object]' || s.includes('placeholder')) return null;
  return s;
}

/**
 * Get the best default image for an ad based on category/subcategory.
 * Priority:
 *   1. ad.images[0] — real uploaded image (string URL or {url} object)
 *   2. subcategory slug → /category-images/{slug}.jpg
 *   3. category slug    → /category-images/{slug}.jpg
 *   4. /category-images/other.jpg
 */
export function getAdDefaultImage(ad) {
  // ── Step 1: real uploaded image ──────────────────────────────────────────
  // Check both 'images' and 'media' fields — backend may populate either or both
  const imgArrays = [ad?.images, ad?.media].filter(a => Array.isArray(a) && a.length > 0);
  for (const arr of imgArrays) {
    const url = extractImageUrl(arr[0]);
    if (url) {
      if (url.startsWith('http') || url.startsWith('data:') || url.startsWith('blob:')) return url;
      if (url.startsWith('/category-images')) return url;
      // Assume Cloudinary public_id
      return `https://res.cloudinary.com/dni9wcvx3/image/upload/f_auto,q_auto,w_400,c_limit/${url}`;
    }
  }

  // ── Step 1b: title keyword lookup ────────────────────────────────────────
  const _title = ((ad?.title || '') + ' ' + (ad?.description || '')).toLowerCase();
  for (const { keywords, image } of TITLE_KEYWORD_MAP) {
    if (keywords.some(kw => _title.includes(kw.toLowerCase()))) {
      return image;
    }
  }

  // ── Step 2: subcategory image ─────────────────────────────────────────────
  const sub = ad?.subcategory;
  if (sub && CATEGORY_IMAGES[sub]) return CATEGORY_IMAGES[sub];

  // ── Step 3: category image ────────────────────────────────────────────────
  const cat = ad?.category;
  if (cat && CATEGORY_IMAGES[cat]) return CATEGORY_IMAGES[cat];

  // ── Step 4: global fallback ───────────────────────────────────────────────
  return `${BASE}/other.jpg`;
}
